8: /**
9:  * Describes how comments for a language work.
10:  */
11: export interface CommentRule {
12: 	/**
13: 	 * The line comment token, like `// this is a comment`
14: 	 */
15: 	lineComment?: string | null;
16: 	/**
17: 	 * The block comment character pair, like `/* block comment *&#47;`
18: 	 */
19: 	blockComment?: CharacterPair | null;
20: }
21: 
22: /**
23:  * The language configuration interface defines the contract between extensions and
24:  * various editor features, like automatic bracket insertion, automatic indentation etc.
25:  */
26: export interface LanguageConfiguration {
27: 	/**
28: 	 * The language's comment settings.
29: 	 */
30: 	comments?: CommentRule;
31: 	/**
32: 	 * The language's brackets.
33: 	 * This configuration implicitly affects pressing Enter around these brackets.
34: 	 */
35: 	brackets?: CharacterPair[];
36: 	/**
37: 	 * The language's word definition.
38: 	 * If the language supports Unicode identifiers (e.g. JavaScript), it is preferable
39: 	 * to provide a word definition that uses exclusion of known separators.
40: 	 * e.g.: A regex that matches anything except known separators (and dot is allowed to occur in a floating point number):
41: 	 *   /(-?\d*\.\d\w*)|([^\`\~\!\@\#\%\^\&\*\(\)\-\=\+\[\{\]\}\\\|\;\:\'\"\,\.\<\>\/\?\s]+)/g
42: 	 */
43: 	wordPattern?: RegExp;
44: 	/**
45: 	 * The language's indentation settings.
46: 	 */
47: 	indentationRules?: IndentationRule;
48: 	/**
49: 	 * The language's rules to be evaluated when pressing Enter.
50: 	 */
51: 	onEnterRules?: OnEnterRule[];
52: 	/**
53: 	 * The language's auto closing pairs. The 'close' character is automatically inserted with the
54: 	 * 'open' character is typed. If not set, the configured brackets will be used.
55: 	 */
56: 	autoClosingPairs?: IAutoClosingPairConditional[];
57: 	/**
58: 	 * The language's surrounding pairs. When the 'open' character is typed on a selection, the
59: 	 * selected string is surrounded by the open and close characters. If not set, the autoclosing pairs
60: 	 * settings will be used.
61: 	 */
62: 	surroundingPairs?: IAutoClosingPair[];
63: 
64: 	/**
65: 	 * Defines what characters must be after the cursor for bracket or quote autoclosing to occur when using the \'languageDefined\' autoclosing setting.
66: 	 *
67: 	 * This is typically the set of characters which can not start an expression, such as whitespace, closing brackets, non-unary operators, etc.
68: 	 */
69: 	autoCloseBefore?: string;
70: 
71: 	/**
72: 	 * The language's folding rules.
73: 	 */
74: 	folding?: FoldingRules;
75: 
76: 	/**
77: 	 * **Deprecated** Do not use.
78: 	 *
79: 	 * @deprecated Will be replaced by a better API soon.
80: 	 */
81: 	__electricCharacterSupport?: {
82: 		docComment?: IDocComment;
83: 	};
84: }
85: 
86: /**
87:  * Describes indentation rules for a language.
88:  */
89: export interface IndentationRule {
90: 	/**
91: 	 * If a line matches this pattern, then all the lines after it should be unindented once (until another rule matches).
92: 	 */
93: 	decreaseIndentPattern: RegExp;
94: 	/**
95: 	 * If a line matches this pattern, then all the lines after it should be indented once (until another rule matches).
96: 	 */
97: 	increaseIndentPattern: RegExp;
98: 	/**
99: 	 * If a line matches this pattern, then **only the next line** after it should be indented once.
100: 	 */
101: 	indentNextLinePattern?: RegExp | null;
102: 	/**
103: 	 * If a line matches this pattern, then its indentation should not be changed and it should not be evaluated against the other rules.
104: 	 */
105: 	unIndentedLinePattern?: RegExp | null;
106: 
107: }
108: 
109: /**
110:  * Describes language specific folding markers such as '#region' and '#endregion'.
111:  * The start and end regexes will be tested against the contents of all lines and must be designed efficiently:
112:  * - the regex should start with '^'
113:  * - regexp flags (i, g) are ignored
114:  */
115: export interface FoldingMarkers {
116: 	start: RegExp;
117: 	end: RegExp;
118: }
119: 
120: /**
121:  * Describes folding rules for a language.
122:  */
123: export interface FoldingRules {
124: 	/**
125: 	 * Used by the indentation based strategy to decide whether empty lines belong to the previous or the next block.
126: 	 * A language adheres to the off-side rule if blocks in that language are expressed by their indentation.
127: 	 * See [wikipedia](https://en.wikipedia.org/wiki/Off-side_rule) for more information.
128: 	 * If not set, `false` is used and empty lines belong to the previous block.
129: 	 */
130: 	offSide?: boolean;
131: 
132: 	/**
133: 	 * Region markers used by the language.
134: 	 */
135: 	markers?: FoldingMarkers;
136: }
137: 
138: /**
139:  * Describes a rule to be evaluated when pressing Enter.
140:  */
141: export interface OnEnterRule {
142: 	/**
143: 	 * This rule will only execute if the text before the cursor matches this regular expression.
144: 	 */
145: 	beforeText: RegExp;
146: 	/**
147: 	 * This rule will only execute if the text after the cursor matches this regular expression.
148: 	 */
149: 	afterText?: RegExp;
150: 	/**
151: 	 * This rule will only execute if the text above the this line matches this regular expression.
152: 	 */
153: 	oneLineAboveText?: RegExp;
154: 	/**
155: 	 * The action to execute.
156: 	 */
157: 	action: EnterAction;
158: }
159: 
160: /**
161:  * Definition of documentation comments (e.g. Javadoc/JSdoc)
162:  */
163: export interface IDocComment {
164: 	/**
165: 	 * The string that starts a doc comment (e.g. '/**')
166: 	 */
167: 	open: string;
168: 	/**
169: 	 * The string that appears on the last line and closes the doc comment (e.g. ' * /').
170: 	 */
171: 	close?: string;
172: }
173: 
174: /**
175:  * A tuple of two characters, like a pair of
176:  * opening and closing brackets.
177:  */
178: export type CharacterPair = [string, string];
179: 
180: export interface IAutoClosingPair {
181: 	open: string;
182: 	close: string;
183: }
184: 
185: export interface IAutoClosingPairConditional extends IAutoClosingPair {
186: 	notIn?: string[];
187: }
