189: /**
190:  * Describes what to do with the indentation when pressing Enter.
191:  */
192: export enum IndentAction {
193: 	/**
194: 	 * Insert new line and copy the previous line's indentation.
195: 	 */
196: 	None = 0,
197: 	/**
198: 	 * Insert new line and indent once (relative to the previous line's indentation).
199: 	 */
200: 	Indent = 1,
201: 	/**
202: 	 * Insert two new lines:
203: 	 *  - the first one indented which will hold the cursor
204: 	 *  - the second one at the same indentation level
205: 	 */
206: 	IndentOutdent = 2,
207: 	/**
208: 	 * Insert new line and outdent once (relative to the previous line's indentation).
209: 	 */
210: 	Outdent = 3
211: }
212: 
213: /**
214:  * Describes what to do when pressing Enter.
215:  */
216: export interface EnterAction {
217: 	/**
218: 	 * Describe what to do with the indentation.
219: 	 */
220: 	indentAction: IndentAction;
221: 	/**
222: 	 * Describes text to be appended after the new line and after the indentation.
223: 	 */
224: 	appendText?: string;
225: 	/**
226: 	 * Describes the number of characters to remove from the new line's indentation.
227: 	 */
228: 	removeText?: number;
229: }
230: 
231: /**
232:  * @internal
233:  */
234: export interface CompleteEnterAction {
235: 	/**
236: 	 * Describe what to do with the indentation.
237: 	 */
238: 	indentAction: IndentAction;
239: 	/**
240: 	 * Describes text to be appended after the new line and after the indentation.
241: 	 */
242: 	appendText: string;
243: 	/**
244: 	 * Describes the number of characters to remove from the new line's indentation.
245: 	 */
246: 	removeText: number;
247: 	/**
248: 	 * The line's indentation minus removeText
249: 	 */
250: 	indentation: string;
251: }
