253: /**
254:  * @internal
255:  */
256: export class StandardAutoClosingPairConditional {
257: 	_standardAutoClosingPairConditionalBrand: void;
258: 
259: 	readonly open: string;
260: 	readonly close: string;
261: 	private readonly _standardTokenMask: number;
262: 
263: 	constructor(source: IAutoClosingPairConditional) {
264: 		this.open = source.open;
265: 		this.close = source.close;
266: 
267: 		// initially allowed in all tokens
268: 		this._standardTokenMask = 0;
269: 
270: 		if (Array.isArray(source.notIn)) {
271: 			for (let i = 0, len = source.notIn.length; i < len; i++) {
272: 				const notIn: string = source.notIn[i];
273: 				switch (notIn) {
274: 					case 'string':
275: 						this._standardTokenMask |= StandardTokenType.String;
276: 						break;
277: 					case 'comment':
278: 						this._standardTokenMask |= StandardTokenType.Comment;
279: 						break;
280: 					case 'regex':
281: 						this._standardTokenMask |= StandardTokenType.RegEx;
282: 						break;
283: 				}
284: 			}
285: 		}
286: 	}
287: 
288: 	public isOK(standardToken: StandardTokenType): boolean {
289: 		return (this._standardTokenMask & <number>standardToken) === 0;
290: 	}
291: }
292: 
293: /**
294:  * @internal
295:  */
296: export class AutoClosingPairs {
297: 
298: 	public readonly autoClosingPairsOpen: Map<string, StandardAutoClosingPairConditional[]>;
299: 	public readonly autoClosingPairsClose: Map<string, StandardAutoClosingPairConditional[]>;
300: 
301: 	constructor(autoClosingPairs: StandardAutoClosingPairConditional[]) {
302: 		this.autoClosingPairsOpen = new Map<string, StandardAutoClosingPairConditional[]>();
303: 		this.autoClosingPairsClose = new Map<string, StandardAutoClosingPairConditional[]>();
304: 		for (const pair of autoClosingPairs) {
305: 			appendEntry(this.autoClosingPairsOpen, pair.open.charAt(pair.open.length - 1), pair);
306: 			if (pair.close.length === 1) {
307: 				appendEntry(this.autoClosingPairsClose, pair.close, pair);
308: 			}
309: 		}
310: 	}
311: }
312: 
313: function appendEntry<K, V>(target: Map<K, V[]>, key: K, value: V): void {
314: 	if (target.has(key)) {
315: 		target.get(key)!.push(value);
316: 	} else {
317: 		target.set(key, [value]);
318: 	}
319: }
