551: 	private static _isAutoClosingOpenCharType(config: CursorConfiguration, model: ITextModel, selections: Selection[], ch: string, insertOpenCharacter: boolean): StandardAutoClosingPairConditional | null {
552: 		const chIsQuote = isQuote(ch);
553: 		const autoCloseConfig = chIsQuote ? config.autoClosingQuotes : config.autoClosingBrackets;
554: 		if (autoCloseConfig === 'never') {
555: 			return null;
556: 		}
557: 
558: 		const autoClosingPair = this._findAutoClosingPairOpen(config, model, selections.map(s => s.getPosition()), ch);
559: 		if (!autoClosingPair) {
560: 			return null;
561: 		}
562: 
563: 		const shouldAutoCloseBefore = chIsQuote ? config.shouldAutoCloseBefore.quote : config.shouldAutoCloseBefore.bracket;
564: 
565: 		for (let i = 0, len = selections.length; i < len; i++) {
566: 			const selection = selections[i];
567: 			if (!selection.isEmpty()) {
568: 				return null;
569: 			}
570: 
571: 			const position = selection.getPosition();
572: 			const lineText = model.getLineContent(position.lineNumber);
573: 
574: 			// Only consider auto closing the pair if a space follows or if another autoclosed pair follows
575: 			if (lineText.length > position.column - 1) {
576: 				const characterAfter = lineText.charAt(position.column - 1);
577: 				const isBeforeCloseBrace = TypeOperations._isBeforeClosingBrace(config, autoClosingPair, characterAfter);
578: 
579: 				if (!isBeforeCloseBrace && !shouldAutoCloseBefore(characterAfter)) {
580: 					return null;
581: 				}
582: 			}
583: 
584: 			if (!model.isCheapToTokenize(position.lineNumber)) {
585: 				// Do not force tokenization
586: 				return null;
587: 			}
588: 
589: 			// Do not auto-close ' or " after a word character
590: 			if (autoClosingPair.open.length === 1 && chIsQuote && autoCloseConfig !== 'always') {
591: 				const wordSeparators = getMapForWordSeparators(config.wordSeparators);
592: 				if (insertOpenCharacter && position.column > 1 && wordSeparators.get(lineText.charCodeAt(position.column - 2)) === WordCharacterClass.Regular) {
