805: 	public static typeWithInterceptors(isDoingComposition: boolean, prevEditOperationType: EditOperationType, config: CursorConfiguration, model: ITextModel, selections: Selection[], autoClosedCharacters: Range[], ch: string): EditOperationResult {
806: 
807: 		if (!isDoingComposition && ch === '\n') {
808: 			let commands: ICommand[] = [];
809: 			for (let i = 0, len = selections.length; i < len; i++) {
810: 				commands[i] = TypeOperations._enter(config, model, false, selections[i]);
811: 			}
812: 			return new EditOperationResult(EditOperationType.Typing, commands, {
813: 				shouldPushStackElementBefore: true,
814: 				shouldPushStackElementAfter: false,
815: 			});
816: 		}
817: 
818: 		if (!isDoingComposition && this._isAutoIndentType(config, model, selections)) {
819: 			let commands: Array<ICommand | null> = [];
820: 			let autoIndentFails = false;
821: 			for (let i = 0, len = selections.length; i < len; i++) {
822: 				commands[i] = this._runAutoIndentType(config, model, selections[i], ch);
823: 				if (!commands[i]) {
824: 					autoIndentFails = true;
825: 					break;
826: 				}
827: 			}
828: 			if (!autoIndentFails) {
829: 				return new EditOperationResult(EditOperationType.Typing, commands, {
830: 					shouldPushStackElementBefore: true,
831: 					shouldPushStackElementAfter: false,
832: 				});
833: 			}
834: 		}
835: 
836: 		if (!isDoingComposition && this._isAutoClosingOvertype(config, model, selections, autoClosedCharacters, ch)) {
837: 			return this._runAutoClosingOvertype(prevEditOperationType, config, model, selections, ch);
838: 		}
839: 
840: 		if (!isDoingComposition) {
841: 			const autoClosingPairOpenCharType = this._isAutoClosingOpenCharType(config, model, selections, ch, true);
842: 			if (autoClosingPairOpenCharType) {
843: 				return this._runAutoClosingOpenCharType(prevEditOperationType, config, model, selections, ch, true, autoClosingPairOpenCharType);
844: 			}
845: 		}
846: 
847: 		if (this._isSurroundSelectionType(config, model, selections, ch)) {
848: 			return this._runSurroundSelectionType(prevEditOperationType, config, model, selections, ch);
849: 		}
850: 
851: 		// Electric characters make sense only when dealing with a single cursor,
852: 		// as multiple cursors typing brackets for example would interfer with bracket matching
853: 		if (!isDoingComposition && this._isTypeInterceptorElectricChar(config, model, selections)) {
854: 			const r = this._typeInterceptorElectricChar(prevEditOperationType, config, model, selections[0], ch);
855: 			if (r) {
856: 				return r;
857: 			}
858: 		}
859: 
860: 		// A simple character type
861: 		let commands: ICommand[] = [];
862: 		for (let i = 0, len = selections.length; i < len; i++) {
863: 			commands[i] = new ReplaceCommand(selections[i], ch);
864: 		}
865: 		let shouldPushStackElementBefore = (prevEditOperationType !== EditOperationType.Typing);
866: 		if (ch === ' ') {
867: 			shouldPushStackElementBefore = true;
868: 		}
869: 		return new EditOperationResult(EditOperationType.Typing, commands, {
870: 			shouldPushStackElementBefore: shouldPushStackElementBefore,
871: 			shouldPushStackElementAfter: false
872: 		});
873: 	}
